In that case, you can create a separate index cache for each index file. This approach ensures that each index file has its own cache, which can be removed independently when the corresponding index file is deleted.

Here's a simple example of how you could implement this in Python:

```python
import os
import pickle
from collections import OrderedDict

class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        os.makedirs(self.cache_dir, exist_ok=True)

    def get(self, index_file):
        cache_file = os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")
        if os.path.exists(cache_file):
            with open(cache_file, "rb") as f:
                return pickle.load(f)
        return None

    def set(self, index_file, data):
        cache_file = os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")
        with open(cache_file, "wb") as f:
            pickle.dump(data, f)

    def delete(self, index_file):
        cache_file = os.path.join(self.cache_dir, f"{os.path.basename(index_file)}.cache")
        if os.path.exists(cache_file):
            os.remove(cache_file)

